mapper.select:
SELECT
	HOMEPAGE_ID, SUPPORT_MANAGE_IDX, START_DATE, END_DATE, LIMIT_REQ_COUNT
FROM 
	FIELD_SUPPORT_MANAGE
WHERE HOMEPAGE_ID = #{homepage_id}		
	AND DELETE_YN = 'N'

		AND SUBSTR(START_DATE, 0, 7) <= #{plan_date}
		AND SUBSTR(END_DATE, 0, 7) >= #{plan_date}

mapper.insert:

		SELECT NVL(MAX(SUPPORT_MANAGE_IDX),0)+1 FROM FIELD_SUPPORT_MANAGE WHERE HOMEPAGE_ID = #{homepage_id}

	INSERT INTO FIELD_SUPPORT_MANAGE ( HOMEPAGE_ID, SUPPORT_MANAGE_IDX, START_DATE, END_DATE, LIMIT_REQ_COUNT, ADD_DATE, ADD_ID )
   	VALUES ( #{homepage_id}, #{support_manage_idx}, #{start_date}, #{end_date}, #{limit_req_count}, SYSDATE, #{add_id} )
